"use client";

import { useTransition, type CSSProperties } from "react";

type Props = {
    jobId: string;
    adId: string;
    /** Textarea id for "Developed Prompt" (may be inside collapsed details). */
    promptTextareaId: string;
    aspectSelectHeaderId: string;
    saveAdPromptAndReferences: (formData: FormData) => Promise<void>;
    generateAdImages: (formData: FormData) => Promise<void>;
};

function stopProp(e: React.SyntheticEvent) {
    e.stopPropagation();
}

const btnSm: CSSProperties = {
    padding: "6px 10px",
    borderRadius: 8,
    fontSize: 12,
    fontWeight: 700,
    cursor: "pointer",
    border: "1px solid var(--borderStrong)",
    whiteSpace: "nowrap",
};

export function AdCollapsibleHeaderActions({
    jobId,
    adId,
    promptTextareaId,
    aspectSelectHeaderId,
    saveAdPromptAndReferences,
    generateAdImages,
}: Props) {
    const [pendingSave, startSave] = useTransition();

    const onSavePrompt = (e: React.MouseEvent) => {
        stopProp(e);
        const el = document.getElementById(
            promptTextareaId
        ) as HTMLTextAreaElement | null;
        const editedPrompt = el?.value ?? "";
        const fd = new FormData();
        fd.set("jobId", jobId);
        fd.set("adId", adId);
        fd.set("editedPrompt", editedPrompt);
        startSave(async () => {
            await saveAdPromptAndReferences(fd);
        });
    };

    return (
        <div
            onClick={stopProp}
            onPointerDown={stopProp}
            style={{
                display: "flex",
                flexWrap: "wrap",
                alignItems: "center",
                gap: 8,
                cursor: "default",
            }}
        >
            <form
                action={generateAdImages}
                style={{
                    display: "inline-flex",
                    flexWrap: "wrap",
                    alignItems: "center",
                    gap: 8,
                }}
            >
                <input type="hidden" name="jobId" value={jobId} />
                <input type="hidden" name="adId" value={adId} />
                <label
                    htmlFor={aspectSelectHeaderId}
                    style={{
                        fontSize: 11,
                        fontWeight: 700,
                        opacity: 0.85,
                        margin: 0,
                    }}
                >
                    Aspect
                </label>
                <select
                    id={aspectSelectHeaderId}
                    name="adAspectRatio"
                    defaultValue="1:1"
                    style={{
                        padding: "5px 8px",
                        borderRadius: 8,
                        border: "1px solid var(--border)",
                        background: "var(--surfaceElevated)",
                        color: "var(--foreground)",
                        fontSize: 12,
                    }}
                >
                    <option value="1:1">1:1</option>
                    <option value="9:16">9:16</option>
                </select>
                <button
                    type="submit"
                    style={{
                        ...btnSm,
                        background: "var(--accent)",
                        color: "#fff",
                        border: "1px solid rgba(124, 58, 237, 0.35)",
                    }}
                >
                    Generate Kie
                </button>
            </form>
            <button
                type="button"
                disabled={pendingSave}
                onClick={onSavePrompt}
                style={{
                    ...btnSm,
                    background: "var(--surfaceElevated)",
                    color: "var(--foreground)",
                    opacity: pendingSave ? 0.65 : 1,
                }}
            >
                {pendingSave ? "Saving…" : "Save prompt"}
            </button>
        </div>
    );
}
